import{_ as o,o as a,c as e,a3 as r}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"服务注册表浏览器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/service-monitor.md","filePath":"user-guide/tools/service-monitor.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/service-monitor.md"};function i(n,t,d,s,h,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="服务注册表浏览器" tabindex="-1">服务注册表浏览器 <a class="header-anchor" href="#服务注册表浏览器" aria-label="Permalink to &quot;服务注册表浏览器&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>服务注册表浏览器是一个<strong>只读的服务发现工具</strong>，它像一个&quot;内部 API 目录&quot;，为你展示当前应用里所有已注册工具服务的完整信息。当你需要了解某个工具提供了哪些能力、各方法的参数签名是什么、或者想查看某个工具是否实现了元数据接口时，不用再去翻源码，直接在这个工具里一目了然。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>自动发现所有已注册服务</strong>：启动后自动扫描并列出系统中所有已注册的工具服务，数量一目了然</li><li><strong>可视化方法签名浏览</strong>：选中某个服务后，可展开查看其每个公开方法的参数名、类型、必填状态、默认值以及返回值类型</li><li><strong>嵌套参数结构展示</strong>：当参数类型为复杂对象时，支持展开查看其内部属性的完整结构，包括嵌套的子属性</li><li><strong>使用方法示例</strong>：对于提供了样例代码的方法，内置代码编辑器会高亮展示调用示例，方便快速复制参考</li><li><strong>元数据实现状态检测</strong>：清晰标识每个服务是否已实现 <code>getMetadata()</code> 方法，帮助开发者排查服务注册问题</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-4-步走" tabindex="-1">首次使用 4 步走 <a class="header-anchor" href="#首次使用-4-步走" aria-label="Permalink to &quot;首次使用 4 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>服务注册表浏览器</strong>，点击进入。你会看到一个左侧为服务列表、右侧为详情面板的两栏布局界面。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注左侧服务列表和右侧详情面板</p></blockquote><p><strong>第二步：浏览已注册服务</strong></p><p>左侧面板列出了当前系统中所有已注册的工具服务，每个条目显示其 <strong>服务 ID</strong>（等宽字体高亮）、<strong>名称</strong> 和 <strong>描述</strong>。面板顶部的标签会实时显示当前工具总数。</p><p>点击任意服务条目，右侧面板会立即切换到该服务的详细信息。</p><blockquote><p>TODO: 截图 - 左侧服务列表，标注服务 ID、名称、描述和工具数量标签</p></blockquote><p><strong>第三步：查看服务基本信息</strong></p><p>选中一个服务后，右侧详情面板顶部会展示该服务的 <strong>基本信息卡片</strong>：</p><ul><li><strong>服务 ID</strong>：服务的唯一标识符</li><li><strong>服务名称</strong>：工具在 UI 中显示的友好名称</li><li><strong>服务描述</strong>：工具的功能简介</li><li><strong>元数据支持</strong>：表示该服务是否实现了 <code>getMetadata()</code> 方法（绿色&quot;已实现&quot;或灰色&quot;未实现&quot;）</li></ul><blockquote><p>TODO: 截图 - 右侧详情面板顶部，标注服务 ID、名称、描述和元数据支持状态</p></blockquote><p><strong>第四步：展开查看方法详情</strong></p><p>如果服务已实现元数据接口，基本信息下方会显示 <strong>可用方法</strong> 区域，列出该服务的所有公开方法及数量。每个方法以可折叠面板展示，点击即可展开查看：</p><ul><li><strong>方法描述</strong>：方法的功能说明</li><li><strong>参数列表</strong>：表格形式展示每个参数的名称、类型、是否必填、描述和默认值</li><li><strong>返回值类型</strong>：以标签形式展示</li><li><strong>使用示例</strong>：如果提供了示例代码，会通过代码编辑器高亮展示</li></ul><blockquote><p>TODO: 截图 - 展开某个方法后的详细内容，标注参数表格、返回值标签和代码示例</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="服务列表-左侧面板" tabindex="-1">服务列表（左侧面板） <a class="header-anchor" href="#服务列表-左侧面板" aria-label="Permalink to &quot;服务列表（左侧面板）&quot;">​</a></h3><p>左侧面板是整个工具的导航入口，它的结构和交互有以下几个要点：</p><h4 id="工具数量统计" tabindex="-1">工具数量统计 <a class="header-anchor" href="#工具数量统计" aria-label="Permalink to &quot;工具数量统计&quot;">​</a></h4><p>面板顶部的标题右侧附带一个标签，实时显示当前系统中已注册的工具总数。如果值为 0，标签变为灰色，下方会显示&quot;暂无已注册的工具&quot;的空状态提示。</p><h4 id="服务条目展示" tabindex="-1">服务条目展示 <a class="header-anchor" href="#服务条目展示" aria-label="Permalink to &quot;服务条目展示&quot;">​</a></h4><p>每个服务条目包含三部分信息：</p><table tabindex="0"><thead><tr><th>信息</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务 ID</strong></td><td>使用等宽字体（Consolas/Monaco）高亮显示，易于与代码中的引用对应</td></tr><tr><td><strong>服务名称</strong></td><td>工具在 UI 中的显示名称（可能为空）</td></tr><tr><td><strong>服务描述</strong></td><td>工具的功能描述，最多显示两行，过长会被截断并显示省略号</td></tr></tbody></table><h4 id="选中状态" tabindex="-1">选中状态 <a class="header-anchor" href="#选中状态" aria-label="Permalink to &quot;选中状态&quot;">​</a></h4><p>点击某个服务条目后，它会高亮显示（带主题色边框和背景），右侧面板同步切换为对应服务的详情。</p><blockquote><p>TODO: 截图 - 对比未选中和选中状态的服务条目样式差异</p></blockquote><h3 id="服务详情面板-右侧面板" tabindex="-1">服务详情面板（右侧面板） <a class="header-anchor" href="#服务详情面板-右侧面板" aria-label="Permalink to &quot;服务详情面板（右侧面板）&quot;">​</a></h3><p>右侧面板展示选中服务的详细信息，分为以下部分：</p><h4 id="服务信息卡片" tabindex="-1">服务信息卡片 <a class="header-anchor" href="#服务信息卡片" aria-label="Permalink to &quot;服务信息卡片&quot;">​</a></h4><p>以 <code>InfoCard</code> 组件承载，使用 <code>el-descriptions</code> 表格布局展示：</p><ul><li>服务 ID 以标签形式展示，更醒目</li><li>元数据支持状态以绿色/灰色标签区分</li></ul><h4 id="可用方法区域" tabindex="-1">可用方法区域 <a class="header-anchor" href="#可用方法区域" aria-label="Permalink to &quot;可用方法区域&quot;">​</a></h4><p>只有服务实现了 <code>getMetadata()</code> 方法时才会显示此区域。方法列表使用 <code>el-collapse</code> 手风琴模式（一次只能展开一个方法）：</p><p><strong>参数表格</strong>：核心信息载体，展示以下列：</p><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td><strong>参数名</strong></td><td>参数的唯一名称</td></tr><tr><td><strong>必填</strong></td><td>红色&quot;必填&quot;标签或灰色&quot;可选&quot;标签</td></tr><tr><td><strong>类型</strong></td><td>参数类型名（如 <code>string</code>、<code>number</code> 或自定义类型），如果类型包含嵌套属性，旁边会显示&quot;X 个&quot;标签</td></tr><tr><td><strong>描述</strong></td><td>参数的功能说明</td></tr><tr><td><strong>默认值</strong></td><td>参数的默认值（如有）</td></tr></tbody></table><p>当类型为复杂对象时，点击该行前面的展开按钮，内部会以嵌套表格展示其子属性的完整结构：</p><blockquote><p>TODO: 截图 - 展开复杂对象参数后展示嵌套属性表格</p></blockquote><p><strong>使用示例展示</strong>：对于提供了调用示例的方法，会通过 <code>RichCodeEditor</code> 组件以 JavaScript 语法高亮展示示例代码。代码只读，不可编辑。</p><blockquote><p>TODO: 截图 - 使用示例代码高亮展示区域</p></blockquote><h3 id="空状态处理" tabindex="-1">空状态处理 <a class="header-anchor" href="#空状态处理" aria-label="Permalink to &quot;空状态处理&quot;">​</a></h3><p>工具在以下三种场景下会显示友好的空状态提示：</p><ul><li><strong>暂无已注册的工具</strong>：系统尚未注册任何工具服务时展示</li><li><strong>请从左侧列表选择一个服务</strong>：刚打开工具尚未选择任何服务时展示</li><li><strong>该服务尚未实现 getMetadata() 方法</strong>：选中服务但未提供元数据时展示</li></ul><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="快速验证服务注册状态" tabindex="-1">快速验证服务注册状态 <a class="header-anchor" href="#快速验证服务注册状态" aria-label="Permalink to &quot;快速验证服务注册状态&quot;">​</a></h3><p>当你开发或调试新工具时，可以用此工具快速验证注册是否成功：</p><ol><li>启动应用后，打开服务注册表浏览器</li><li>查看左侧列表中的工具总数是否增加了</li><li>找到新工具，检查其基本信息是否正确</li><li>展开方法列表，确认每个方法的参数签名是否与预期一致</li></ol><h3 id="跨工具协作参考" tabindex="-1">跨工具协作参考 <a class="header-anchor" href="#跨工具协作参考" aria-label="Permalink to &quot;跨工具协作参考&quot;">​</a></h3><p>当你在使用其他工具（如 <strong>工具调用测试</strong>、<strong>API 测试工具</strong>）时，可以切换到服务注册表浏览器来快速查阅某个服务提供了哪些方法、各方法需要什么参数。这比翻阅源码文档要高效得多。</p><p>例如：</p><ol><li>在 <strong>工具调用测试</strong> 中准备调用某个服务</li><li>切换到服务注册表浏览器找到该服务，查看其方法的参数签名和示例</li><li>再回到测试工具，根据获取到的信息正确填写参数</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么我的工具没有出现在服务列表中" tabindex="-1">Q：为什么我的工具没有出现在服务列表中？ <a class="header-anchor" href="#q-为什么我的工具没有出现在服务列表中" aria-label="Permalink to &quot;Q：为什么我的工具没有出现在服务列表中？&quot;">​</a></h3><p>这通常意味着该工具未正确注册。请检查以下几点：</p><ul><li>工具目录下是否包含 <code>.registry.ts</code> 文件</li><li>文件中是否正确导出了 <code>toolConfig</code> 配置</li><li>如果工具是一个服务实现，是否已通过 <code>toolRegistryManager.register()</code> 注册</li></ul><h3 id="q-元数据支持-显示为-未实现-是什么意思" tabindex="-1">Q：&quot;元数据支持&quot;显示为&quot;未实现&quot;是什么意思？ <a class="header-anchor" href="#q-元数据支持-显示为-未实现-是什么意思" aria-label="Permalink to &quot;Q：&quot;元数据支持&quot;显示为&quot;未实现&quot;是什么意思？&quot;">​</a></h3><p>这说明该服务（<code>ToolRegistry</code>）没有实现 <code>getMetadata()</code> 方法。<code>getMetadata()</code> 是一个可选方法，用于向外部暴露服务的详细方法签名和参数信息。未实现此方法不会影响工具的正常运行，但在服务注册表浏览器中无法查看其方法详情。</p><h3 id="q-为什么有的参数行前面有一个展开按钮" tabindex="-1">Q：为什么有的参数行前面有一个展开按钮？ <a class="header-anchor" href="#q-为什么有的参数行前面有一个展开按钮" aria-label="Permalink to &quot;Q：为什么有的参数行前面有一个展开按钮？&quot;">​</a></h3><p>当参数的类型为<strong>复杂对象</strong>（如 <code>GenerateTreeOptions</code> 这类自定义类型）时，点击展开按钮可以查看该对象的内部属性列表。嵌套属性的结构与参数表格一致，也支持继续展开更深层的子对象。</p><h3 id="q-方法列表为什么一次只能展开一个" tabindex="-1">Q：方法列表为什么一次只能展开一个？ <a class="header-anchor" href="#q-方法列表为什么一次只能展开一个" aria-label="Permalink to &quot;Q：方法列表为什么一次只能展开一个？&quot;">​</a></h3><p>右侧的可用方法列表使用了手风琴模式（Accordion），这是为了避免多个方法同时展开导致页面信息过载。如果你需要对比两个方法的详情，可以收起当前方法后再展开另一个。实际使用中，一次聚焦一个方法通常更高效。</p><h3 id="q-使用示例里的代码可以复制吗" tabindex="-1">Q：使用示例里的代码可以复制吗？ <a class="header-anchor" href="#q-使用示例里的代码可以复制吗" aria-label="Permalink to &quot;Q：使用示例里的代码可以复制吗？&quot;">​</a></h3><p>可以。示例代码由 <code>RichCodeEditor</code> 组件展示，虽然是只读模式，但你可以像在普通编辑器中一样选中并复制代码片段。</p>',69)])])}const q=o(l,[["render",i]]);export{g as __pageData,q as default};
